 22	// TailSessionLogs watches the agent log directory for new/modified session log
 23	// files and writes formatted progress to dst. It stops when ctx is cancelled.
 24	// Callers should run this in a goroutine while ExecuteBead runs synchronously.
 25	func TailSessionLogs(ctx context.Context, projectRoot string, dst io.Writer) {
 26		logDir := filepath.Join(projectRoot, DefaultLogDir)
 27		states := make(map[string]*fileTrackState)
 28	
 29		// Record existing files so we don't replay old logs
 30		for _, file := range listSessionLogFiles(projectRoot, logDir) {
 31			if info, err := os.Stat(file.path); err == nil {
 32				states[file.path] = &fileTrackState{offset: info.Size()}
 33			}
 34		}
 35	
 36		ticker := time.NewTicker(500 * time.Millisecond)
 37		defer ticker.Stop()
 38	
 39		for {
 40			select {
 41			case <-ctx.Done():
 42				readNewLogLines(projectRoot, logDir, states, dst)
 43				return
 44			case <-ticker.C:
 45				readNewLogLines(projectRoot, logDir, states, dst)
 46			}
 47		}
 48	}
 49	
 50	// readNewLogLines reads any new lines from agent session logs and formats them.
 51	func readNewLogLines(projectRoot, logDir string, states map[string]*fileTrackState, dst io.Writer) {
 52		for _, file := range listSessionLogFiles(projectRoot, logDir) {
 53			path := file.path
 54			st, err := os.Stat(path)
 55			if err != nil {
 56				continue
 57			}
 58	
 59			fs, ok := states[path]
 60			if !ok {
 61				fs = &fileTrackState{}
 62				states[path] = fs
 63			}
 64	
 65			if st.Size() <= fs.offset {
 66				continue
 67			}
 68	
 69			f, err := os.Open(path)
 70			if err != nil {
 71				continue
 72			}
 73	
 74			_, _ = f.Seek(fs.offset, io.SeekStart)
 75			scanner := bufio.NewScanner(f)
 76			// 16MB max line. Session-log `response` fields observed up to ~7MB in
 77			// real incidents (2026-04-20 reviewer-malfunction report). Matches bead
 78			// store and claude stream for consistency.
 79			scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
 80			var newLines []string
 81			for scanner.Scan() {
 82				line := scanner.Text()
 83				if strings.TrimSpace(line) != "" {
 84					newLines = append(newLines, line)
 85				}
 86			}
 87			fs.offset, _ = f.Seek(0, io.SeekCurrent)
 88			f.Close()
 89	
 90			if len(newLines) > 0 {
 91				formatted := FormatSessionLogLines(newLines)
 92				if formatted != "" {
 93					fmt.Fprint(dst, formatted)
 94				}
 95			}
 96		}
 97	}
