 99	func listSessionLogFiles(projectRoot, logDir string) []sessionLogFile {
100		var files []sessionLogFile
101		appendDirLogs := func(dir string) {
102			entries, err := os.ReadDir(dir)
103			if err != nil {
104				return
105			}
106			for _, entry := range entries {
107				if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".jsonl") {
108					continue
109				}
110				name := entry.Name()
111				if strings.HasPrefix(name, "agent-loop-") {
112					continue
113				}
114				if strings.HasPrefix(name, "agent-") || strings.HasPrefix(name, "svc-") {
115					files = append(files, sessionLogFile{path: filepath.Join(dir, name)})
116				}
117			}
118		}
119	
120		appendDirLogs(logDir)
